 34 |     pub fn with_base_url(token: String, base_url: String, provider_name: &str) -> Result<Self> {
 35 |         Ok(Self {
 36 |             client: Client::new(),
 37 |             token,
 38 |             base_url: base_url.trim_end_matches('/').to_string(),
 39 |             provider_name: provider_name.to_string(),
 40 |         })
 41 |     }
