166 |     /// Discover models dynamically from the Copilot /models API endpoint.
167 |     async fn discover_models_from_api(&self) -> Vec<ModelInfo> {
168 |         let response = match self
169 |             .client
170 |             .get(format!("{}/models", self.base_url))
171 |             .header("Authorization", format!("Bearer {}", self.token))
172 |             .header("User-Agent", Self::user_agent())
173 |             .send()
174 |             .await
175 |         {
176 |             Ok(r) => r,
177 |             Err(e) => {
178 |                 tracing::warn!(provider = %self.provider_name, error = %e, "Failed to fetch Copilot models endpoint");
179 |                 return Vec::new();
180 |             }
181 |         };
182 | 
183 |         let status = response.status();
184 |         if !status.is_success() {
185 |             let body = response.text().await.unwrap_or_default();
186 |             tracing::warn!(
187 |                 provider = %self.provider_name,
188 |                 status = %status,
189 |                 body = %body.chars().take(200).collect::<String>(),
190 |                 "Copilot /models endpoint returned non-success"
191 |             );
192 |             return Vec::new();
193 |         }
194 | 
195 |         let parsed: CopilotModelsResponse = match response.json().await {
196 |             Ok(p) => p,
197 |             Err(e) => {
198 |                 tracing::warn!(provider = %self.provider_name, error = %e, "Failed to parse Copilot models response");
199 |                 return Vec::new();
200 |             }
201 |         };
202 | 
203 |         let models: Vec<ModelInfo> = parsed
204 |             .data
205 |             .into_iter()
206 |             .filter(|model| {
207 |                 // Skip models with a disabled policy state (truly unavailable)
208 |                 // Note: model_picker_enabled only controls VS Code UI, not API availability
209 |                 if let Some(ref policy) = model.policy
210 |                     && policy.state.as_deref() == Some("disabled")
211 |                 {
212 |                     return false;
213 |                 }
214 |                 true
215 |             })
216 |             .map(|model| {
217 |                 let caps = model.capabilities.as_ref();
218 |                 let limits = caps.and_then(|c| c.limits.as_ref());
219 |                 let supports = caps.and_then(|c| c.supports.as_ref());
220 | 
221 |                 ModelInfo {
222 |                     id: model.id.clone(),
223 |                     name: model.name.unwrap_or_else(|| model.id.clone()),
224 |                     provider: self.provider_name.clone(),
225 |                     context_window: limits
226 |                         .and_then(|l| l.max_context_window_tokens)
227 |                         .unwrap_or(128_000),
228 |                     max_output_tokens: limits.and_then(|l| l.max_output_tokens).or(Some(16_384)),
229 |                     supports_vision: supports.and_then(|s| s.vision).unwrap_or(false),
230 |                     supports_tools: supports.and_then(|s| s.tool_calls).unwrap_or(true),
231 |                     supports_streaming: supports.and_then(|s| s.streaming).unwrap_or(true),
232 |                     input_cost_per_million: None,
233 |                     output_cost_per_million: None,
234 |                 }
235 |             })
236 |             .collect();
237 | 
238 |         tracing::info!(
239 |             provider = %self.provider_name,
240 |             count = models.len(),
241 |             "Discovered models from Copilot API"
242 |         );
243 |         models
244 |     }
