246 |     /// Enrich models with pricing metadata from known premium request multipliers.
247 |     ///
248 |     /// Source: https://docs.github.com/en/copilot/concepts/billing/copilot-requests
249 |     /// Cost model: Premium requests at $0.04/request overflow rate.
250 |     /// We convert multiplier to approximate $/M tokens using ~4K tokens/request avg.
251 |     /// Formula: multiplier * $0.04 / 4K tokens * 1M = multiplier * $10/M tokens.
252 |     fn enrich_with_pricing(&self, models: &mut [ModelInfo]) {
253 |         // (display_name, premium_multiplier)
254 |         let pricing: std::collections::HashMap<&str, (&str, f64)> = [
255 |             ("claude-opus-4.5", ("Claude Opus 4.5", 3.0)),
256 |             ("claude-opus-4.6", ("Claude Opus 4.6", 3.0)),
257 |             ("claude-opus-41", ("Claude Opus 4.1", 10.0)),
258 |             ("claude-sonnet-4-6", ("Claude Sonnet 4.6", 1.0)),
259 |             ("claude-sonnet-4.5", ("Claude Sonnet 4.5", 1.0)),
260 |             ("claude-sonnet-4", ("Claude Sonnet 4", 1.0)),
261 |             ("claude-haiku-4.5", ("Claude Haiku 4.5", 0.33)),
262 |             ("gpt-5.3-codex", ("GPT-5.3-Codex", 1.0)),
263 |             ("gpt-5.2", ("GPT-5.2", 1.0)),
264 |             ("gpt-5.2-codex", ("GPT-5.2-Codex", 1.0)),
265 |             ("gpt-5.1", ("GPT-5.1", 1.0)),
266 |             ("gpt-5.1-codex", ("GPT-5.1-Codex", 1.0)),
267 |             ("gpt-5.1-codex-mini", ("GPT-5.1-Codex-Mini", 0.33)),
268 |             ("gpt-5.1-codex-max", ("GPT-5.1-Codex-Max", 1.0)),
269 |             ("gpt-5", ("GPT-5", 1.0)),
270 |             ("gpt-5-mini", ("GPT-5 mini", 0.0)),
271 |             ("gpt-5-codex", ("GPT-5-Codex", 1.0)),
272 |             ("gpt-4.1", ("GPT-4.1", 0.0)),
273 |             ("gpt-4o", ("GPT-4o", 0.0)),
274 |             ("gemini-2.5-pro", ("Gemini 2.5 Pro", 1.0)),
275 |             ("gemini-3.1-pro-preview", ("Gemini 3.1 Pro Preview", 1.0)),
276 |             (
277 |                 "gemini-3.1-pro-preview-customtools",
278 |                 ("Gemini 3.1 Pro Preview (Custom Tools)", 1.0),
279 |             ),
280 |             ("gemini-3-flash-preview", ("Gemini 3 Flash Preview", 0.33)),
281 |             ("gemini-3-pro-preview", ("Gemini 3 Pro Preview", 1.0)),
282 |             (
283 |                 "gemini-3-pro-image-preview",
284 |                 ("Gemini 3 Pro Image Preview", 1.0),
285 |             ),
286 |             ("grok-code-fast-1", ("Grok Code Fast 1", 0.25)),
287 |         ]
288 |         .into_iter()
289 |         .collect();
290 | 
291 |         for model in models.iter_mut() {
292 |             if let Some((display_name, premium_mult)) = pricing.get(model.id.as_str()) {
293 |                 // Set a friendlier display name when the API only returned the raw id
294 |                 if model.name == model.id {
295 |                     model.name = display_name.to_string();
296 |                 }
297 |                 let approx_cost = premium_mult * 10.0;
298 |                 model.input_cost_per_million = Some(approx_cost);
299 |                 model.output_cost_per_million = Some(approx_cost);
300 |             } else {
301 |                 // Unknown Copilot model — assume 1x premium request ($10/M approx)
302 |                 if model.input_cost_per_million.is_none() {
303 |                     model.input_cost_per_million = Some(10.0);
304 |                 }
305 |                 if model.output_cost_per_million.is_none() {
306 |                     model.output_cost_per_million = Some(10.0);
307 |                 }
308 |             }
309 |         }
310 |     }
