506 | #[async_trait]
507 | impl Provider for CopilotProvider {
508 |     fn name(&self) -> &str {
509 |         &self.provider_name
510 |     }
511 | 
512 |     async fn list_models(&self) -> Result<Vec<ModelInfo>> {
513 |         let mut models = self.discover_models_from_api().await;
514 | 
515 |         // If API discovery returned nothing, fall back to known models
516 |         if models.is_empty() {
517 |             tracing::info!(provider = %self.provider_name, "No models from API, using known model catalog");
518 |             models = self.known_models();
519 |         }
520 | 
521 |         // Enrich with pricing metadata from known premium request multipliers
522 |         self.enrich_with_pricing(&mut models);
523 | 
524 |         // Filter out non-chat models (embeddings, etc.) and legacy dated variants
525 |         models.retain(|m| {
526 |             !m.id.starts_with("text-embedding")
527 |                 && !m.id.contains("-embedding-")
528 |                 && !is_dated_model_variant(&m.id)
529 |         });
530 | 
531 |         // Deduplicate by id (API sometimes returns duplicates)
532 |         let mut seen = std::collections::HashSet::new();
533 |         models.retain(|m| seen.insert(m.id.clone()));
534 | 
535 |         Ok(models)
536 |     }
537 | 
538 |     async fn complete(&self, request: CompletionRequest) -> Result<CompletionResponse> {
539 |         let messages = Self::convert_messages(&request.messages);
540 |         let tools = Self::convert_tools(&request.tools);
541 |         let is_agent = Self::is_agent_initiated(&request.messages);
542 |         let has_vision = Self::has_vision_input(&request.messages);
543 | 
544 |         let mut body = json!({
545 |             "model": request.model,
546 |             "messages": messages,
547 |         });
548 | 
549 |         if !tools.is_empty() {
550 |             body["tools"] = json!(tools);
551 |         }
552 |         if let Some(temp) = request.temperature {
553 |             body["temperature"] = json!(temp);
554 |         }
555 |         if let Some(top_p) = request.top_p {
556 |             body["top_p"] = json!(top_p);
557 |         }
558 |         if let Some(max) = request.max_tokens {
559 |             body["max_tokens"] = json!(max);
560 |         }
561 |         if !request.stop.is_empty() {
562 |             body["stop"] = json!(request.stop);
563 |         }
564 | 
565 |         let mut req = self
566 |             .client
567 |             .post(format!("{}/chat/completions", self.base_url))
568 |             .header("Authorization", format!("Bearer {}", self.token))
569 |             .header("Content-Type", "application/json")
570 |             .header("Openai-Intent", "conversation-edits")
571 |             .header("User-Agent", Self::user_agent())
572 |             .header("X-Initiator", if is_agent { "agent" } else { "user" });
573 | 
574 |         if has_vision {
575 |             req = req.header("Copilot-Vision-Request", "true");
576 |         }
577 | 
578 |         let response = req
579 |             .json(&body)
580 |             .send()
581 |             .await
582 |             .context("Failed to send Copilot request")?;
583 | 
584 |         let status = response.status();
585 |         let text = response
586 |             .text()
587 |             .await
588 |             .context("Failed to read Copilot response")?;
589 | 
590 |         if !status.is_success() {
591 |             if let Ok(err) = serde_json::from_str::<CopilotErrorResponse>(&text) {
592 |                 let message = err
593 |                     .error
594 |                     .and_then(|detail| {
595 |                         detail.message.map(|msg| {
596 |                             if let Some(code) = detail.code {
597 |                                 format!("{} ({})", msg, code)
598 |                             } else {
599 |                                 msg
600 |                             }
601 |                         })
602 |                     })
603 |                     .or(err.message)
604 |                     .unwrap_or_else(|| "Unknown Copilot API error".to_string());
605 |                 anyhow::bail!("Copilot API error: {}", message);
606 |             }
607 |             anyhow::bail!("Copilot API error: {} {}", status, text);
608 |         }
609 | 
610 |         let response: CopilotResponse = serde_json::from_str(&text).context(format!(
611 |             "Failed to parse Copilot response: {}",
612 |             &text[..text.len().min(200)]
613 |         ))?;
614 | 
615 |         let choice = response
616 |             .choices
617 |             .first()
618 |             .ok_or_else(|| anyhow::anyhow!("No choices"))?;
619 | 
620 |         let mut content = Vec::new();
621 |         let mut has_tool_calls = false;
622 | 
623 |         if let Some(text) = &choice.message.content
624 |             && !text.is_empty()
625 |         {
626 |             content.push(ContentPart::Text { text: text.clone() });
627 |         }
628 | 
629 |         if let Some(tool_calls) = &choice.message.tool_calls {
630 |             has_tool_calls = !tool_calls.is_empty();
631 |             for tc in tool_calls {
632 |                 content.push(ContentPart::ToolCall {
633 |                     id: tc.id.clone(),
634 |                     name: tc.function.name.clone(),
635 |                     arguments: tc.function.arguments.clone(),
636 |                     thought_signature: None,
637 |                 });
638 |             }
639 |         }
640 | 
641 |         let finish_reason = if has_tool_calls {
642 |             FinishReason::ToolCalls
643 |         } else {
644 |             match choice.finish_reason.as_deref() {
645 |                 Some("stop") => FinishReason::Stop,
646 |                 Some("length") => FinishReason::Length,
647 |                 Some("tool_calls") => FinishReason::ToolCalls,
648 |                 Some("content_filter") => FinishReason::ContentFilter,
649 |                 _ => FinishReason::Stop,
650 |             }
651 |         };
652 | 
653 |         Ok(CompletionResponse {
654 |             message: Message {
655 |                 role: Role::Assistant,
656 |                 content,
657 |             },
658 |             usage: Usage {
659 |                 prompt_tokens: response
660 |                     .usage
661 |                     .as_ref()
662 |                     .map(|u| u.prompt_tokens)
663 |                     .unwrap_or(0),
664 |                 completion_tokens: response
665 |                     .usage
666 |                     .as_ref()
667 |                     .map(|u| u.completion_tokens)
668 |                     .unwrap_or(0),
669 |                 total_tokens: response.usage.as_ref().map(|u| u.total_tokens).unwrap_or(0),
670 |                 ..Default::default()
671 |             },
672 |             finish_reason,
673 |         })
674 |     }
675 | 
676 |     async fn complete_stream(
677 |         &self,
678 |         request: CompletionRequest,
679 |     ) -> Result<futures::stream::BoxStream<'static, StreamChunk>> {
680 |         // For now, keep behavior aligned with other non-streaming providers.
681 |         let response = self.complete(request).await?;
682 |         let text = response
683 |             .message
684 |             .content
685 |             .iter()
686 |             .filter_map(|p| match p {
687 |                 ContentPart::Text { text } => Some(text.clone()),
688 |                 _ => None,
689 |             })
690 |             .collect::<Vec<_>>()
691 |             .join("");
692 | 
693 |         Ok(Box::pin(futures::stream::once(async move {
694 |             StreamChunk::Text(text)
695 |         })))
696 |     }
697 | }
