699 | /// Check if a model ID is a dated variant (e.g. "gpt-4o-2024-05-13") that should
700 | /// be filtered out in favor of the canonical alias (e.g. "gpt-4o").
701 | fn is_dated_model_variant(id: &str) -> bool {
702 |     // Match IDs ending in a YYYY-MM-DD date suffix
703 |     let bytes = id.as_bytes();
704 |     if bytes.len() < 11 {
705 |         return false;
706 |     }
707 |     // Check for "-YYYY-MM-DD" at end
708 |     let tail = &id[id.len() - 11..];
709 |     tail.starts_with('-')
710 |         && tail[1..5].bytes().all(|b| b.is_ascii_digit())
711 |         && tail.as_bytes()[5] == b'-'
712 |         && tail[6..8].bytes().all(|b| b.is_ascii_digit())
713 |         && tail.as_bytes()[8] == b'-'
714 |         && tail[9..11].bytes().all(|b| b.is_ascii_digit())
715 | }
