 304 |     /// Register a provider (automatically wrapped with metrics instrumentation)
 305 |     pub fn register(&mut self, provider: Arc<dyn Provider>) {
 306 |         let name = provider.name().to_string();
 307 |         let wrapped = metrics::MetricsProvider::wrap(provider);
 308 |         self.providers.insert(name, wrapped);
 309 |     }
 310 | 
 311 |     /// Get a provider by name
 312 |     pub fn get(&self, name: &str) -> Option<Arc<dyn Provider>> {
 313 |         self.providers.get(name).cloned()
 314 |     }
 315 | 
 316 |     /// List all registered providers
 317 |     pub fn list(&self) -> Vec<&str> {
 318 |         self.providers.keys().map(|s| s.as_str()).collect()
 319 |     }
