 358 |     /// Initialize with default providers from config
 359 |     pub async fn from_config(config: &crate::config::Config) -> Result<Self> {
 360 |         let mut registry = Self::new();
 361 | 
 362 |         // Always try to initialize OpenAI if key is available
 363 |         if let Some(provider_config) = config.providers.get("openai") {
 364 |             if let Some(api_key) = &provider_config.api_key {
 365 |                 registry.register(Arc::new(openai::OpenAIProvider::new(api_key.clone())?));
 366 |             }
 367 |         } else if let Ok(api_key) = std::env::var("OPENAI_API_KEY") {
 368 |             registry.register(Arc::new(openai::OpenAIProvider::new(api_key)?));
 369 |         }
 370 | 
 371 |         // Initialize Anthropic
 372 |         if let Some(provider_config) = config.providers.get("anthropic") {
 373 |             if let Some(api_key) = &provider_config.api_key {
 374 |                 let provider = if let Some(base_url) = provider_config.base_url.clone() {
 375 |                     anthropic::AnthropicProvider::with_base_url(
 376 |                         api_key.clone(),
 377 |                         base_url,
 378 |                         "anthropic",
 379 |                     )?
 380 |                 } else {
 381 |                     anthropic::AnthropicProvider::new(api_key.clone())?
 382 |                 };
 383 |                 registry.register(Arc::new(provider));
 384 |             }
 385 |         } else if let Ok(api_key) = std::env::var("ANTHROPIC_API_KEY") {
 386 |             registry.register(Arc::new(anthropic::AnthropicProvider::new(api_key)?));
 387 |         }
 388 | 
 389 |         // Initialize Google
 390 |         if let Some(provider_config) = config.providers.get("google") {
 391 |             if let Some(api_key) = &provider_config.api_key {
 392 |                 registry.register(Arc::new(google::GoogleProvider::new(api_key.clone())?));
 393 |             }
 394 |         } else if let Ok(api_key) = std::env::var("GOOGLE_API_KEY") {
 395 |             registry.register(Arc::new(google::GoogleProvider::new(api_key)?));
 396 |         }
 397 | 
 398 |         // Initialize Novita (OpenAI-compatible)
 399 |         if let Some(provider_config) = config.providers.get("novita")
 400 |             && let Some(api_key) = &provider_config.api_key
 401 |         {
 402 |             let base_url = provider_config
 403 |                 .base_url
 404 |                 .clone()
 405 |                 .unwrap_or_else(|| "https://api.novita.ai/openai/v1".to_string());
 406 |             registry.register(Arc::new(openai::OpenAIProvider::with_base_url(
 407 |                 api_key.clone(),
 408 |                 base_url,
 409 |                 "novita",
 410 |             )?));
 411 |         }
 412 | 
 413 |         // Initialize Bedrock via AWS credentials (env vars or ~/.aws/credentials)
 414 |         if let Some(creds) = bedrock::AwsCredentials::from_environment() {
 415 |             let region = bedrock::AwsCredentials::detect_region()
 416 |                 .unwrap_or_else(|| bedrock::DEFAULT_REGION.to_string());
 417 |             match bedrock::BedrockProvider::with_credentials(creds, region) {
 418 |                 Ok(p) => registry.register(Arc::new(p)),
 419 |                 Err(e) => tracing::warn!("Failed to init bedrock from AWS credentials: {}", e),
 420 |             }
 421 |         }
 422 | 
 423 |         let disable_env_fallback = std::env::var("CODETETHER_DISABLE_ENV_FALLBACK")
 424 |             .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
 425 |             .unwrap_or(false);
 426 |         if !disable_env_fallback {
 427 |             Self::register_env_fallbacks(&mut registry);
 428 |         } else {
 429 |             tracing::info!(
 430 |                 "Environment variable fallback disabled (CODETETHER_DISABLE_ENV_FALLBACK=1)"
 431 |             );
 432 |         }
 433 | 
 434 |         Ok(registry)
 435 |     }
