 625 |                     let expires_at = secrets.extra.get("expires_at").and_then(|v| v.as_u64());
 626 |                     let id_token = secrets.extra.get("id_token").and_then(|v| v.as_str());
 627 |                     let chatgpt_account_id = secrets
 628 |                         .extra
 629 |                         .get("chatgpt_account_id")
 630 |                         .and_then(|v| v.as_str());
 631 |                     let exchanged_api_key =
 632 |                         secrets.api_key.as_deref().filter(|key| !key.is_empty());
 633 | 
 634 |                     if let Some(api_key) = exchanged_api_key {
 635 |                         let provider =
 636 |                             openai_codex::OpenAiCodexProvider::from_api_key(api_key.to_string());
 637 |                         registry.register(Arc::new(provider));
 638 |                     } else {
 639 |                         match (access_token, refresh_token, expires_at) {
 640 |                             (Some(access), Some(refresh), Some(expires)) => {
 641 |                                 let creds = openai_codex::OAuthCredentials {
 642 |                                     id_token: id_token.map(ToString::to_string),
 643 |                                     chatgpt_account_id: chatgpt_account_id.map(ToString::to_string),
 644 |                                     access_token: access.to_string(),
