 994 |     /// Register providers from environment variables if they aren't already registered.
 995 |     ///
 996 |     /// This function provides a convenience fallback for local development by reading
 997 |     /// API keys from environment variables when providers are not configured in Vault.
 998 |     ///
 999 |     /// # Supported Environment Variables
1000 |     ///
1001 |     /// - `OPENAI_API_KEY` → Registers OpenAI provider
1002 |     /// - `ANTHROPIC_API_KEY` → Registers Anthropic provider
1003 |     /// - `GOOGLE_API_KEY` → Registers Google provider
1004 |     /// - `OPENROUTER_API_KEY` → Registers OpenRouter provider
1005 |     /// - `HF_BASE_URL`/`HUGGINGFACE_BASE_URL` (+ optional `HF_TOKEN`/`HUGGINGFACE_API_KEY`) → Registers Hugging Face provider
1006 |     /// - `CODETETHER_LOCAL_CUDA=1` (or `LOCAL_CUDA_MODEL*`) → Registers Local CUDA provider
1007 |     ///
1008 |     /// # Security Warning
1009 |     ///
1010 |     /// Environment variables are less secure than Vault secrets because they:
1011 |     /// - Can be leaked via process listings (`ps eww`) or container inspection
1012 |     /// - May appear in debug logs or error messages
1013 |     /// - Persist in shell history and dotfiles
1014 |     /// - Are accessible to all child processes
1015 |     ///
1016 |     /// For production deployments, set `CODETETHER_DISABLE_ENV_FALLBACK=1` to disable
1017 |     /// this fallback mechanism entirely. See [`from_vault()`](#method.from_vault) for details.
1018 |     ///
1019 |     /// # Behavior
1020 |     ///
1021 |     /// This function only registers a provider if:
1022 |     /// 1. The provider is not already registered (via Vault or earlier initialization)
1023 |     /// 2. The corresponding environment variable is set and non-empty
1024 |     fn register_env_fallbacks(registry: &mut Self) {
1025 |         let fallbacks: &[(&str, &str, fn(String) -> Result<Arc<dyn Provider>>)] = &[
1026 |             ("openai", "OPENAI_API_KEY", |key| {
1027 |                 Ok(Arc::new(openai::OpenAIProvider::new(key)?))
1028 |             }),
1029 |             ("anthropic", "ANTHROPIC_API_KEY", |key| {
1030 |                 Ok(Arc::new(anthropic::AnthropicProvider::new(key)?))
1031 |             }),
1032 |             ("google", "GOOGLE_API_KEY", |key| {
1033 |                 Ok(Arc::new(google::GoogleProvider::new(key)?))
1034 |             }),
1035 |             ("openrouter", "OPENROUTER_API_KEY", |key| {
1036 |                 Ok(Arc::new(openrouter::OpenRouterProvider::new(key)?))
1037 |             }),
1038 |         ];
1039 | 
1040 |         for (provider_id, env_var, constructor) in fallbacks {
1041 |             if !registry.providers.contains_key(*provider_id)
1042 |                 && let Ok(api_key) = std::env::var(env_var)
1043 |             {
1044 |                 match constructor(api_key) {
1045 |                     Ok(p) => {
1046 |                         tracing::info!(
1047 |                             "Registered {} provider from {} env var",
1048 |                             provider_id,
1049 |                             env_var
1050 |                         );
1051 |                         registry.register(p);
1052 |                     }
1053 |                     Err(e) => tracing::warn!("Failed to init {} from env: {}", provider_id, e),
1054 |                 }
1055 |             }
1056 |         }
1057 | 
1058 |         if !registry.providers.contains_key("huggingface") {
1059 |             let huggingface_base_url = std::env::var("HF_BASE_URL")
1060 |                 .ok()
1061 |                 .or_else(|| std::env::var("HUGGINGFACE_BASE_URL").ok())
1062 |                 .or_else(|| std::env::var("HUGGINGFACE_ENDPOINT").ok());
1063 | 
1064 |             if let Some(base_url) = huggingface_base_url {
1065 |                 let api_key = std::env::var("HF_TOKEN")
1066 |                     .ok()
1067 |                     .or_else(|| std::env::var("HUGGINGFACE_API_KEY").ok())
1068 |                     .filter(|value| !value.trim().is_empty());
1069 | 
1070 |                 match openai::OpenAIProvider::with_base_url_optional_key(
1071 |                     api_key,
1072 |                     base_url,
1073 |                     "huggingface",
1074 |                 ) {
1075 |                     Ok(p) => {
1076 |                         tracing::info!(
1077 |                             "Registered huggingface provider from HF_BASE_URL/HUGGINGFACE_BASE_URL env vars"
1078 |                         );
1079 |                         registry.register(Arc::new(p));
1080 |                     }
1081 |                     Err(e) => tracing::warn!("Failed to init huggingface from env: {}", e),
1082 |                 }
1083 |             }
1084 |         }
1085 | 
1086 |         // GLM-5 FP8 on Vast.ai — requires GLM5_BASE_URL; GLM5_API_KEY is optional
1087 |         if !registry.providers.contains_key("glm5")
1088 |             && let Ok(base_url) = std::env::var("GLM5_BASE_URL")
1089 |         {
1090 |             let api_key = std::env::var("GLM5_API_KEY").unwrap_or_default();
1091 |             let model_name =
1092 |                 std::env::var("GLM5_MODEL").unwrap_or_else(|_| glm5::DEFAULT_MODEL.to_string());
1093 |             match glm5::Glm5Provider::with_model(api_key, base_url, model_name) {
1094 |                 Ok(p) => {
1095 |                     tracing::info!("Registered glm5 provider from GLM5_BASE_URL env var");
1096 |                     registry.register(Arc::new(p));
1097 |                 }
1098 |                 Err(e) => tracing::warn!("Failed to init glm5 from env: {}", e),
1099 |             }
1100 |         }
1101 | 
1102 |         if !registry.providers.contains_key("local_cuda") {
1103 |             let local_cuda_enabled = std::env::var("CODETETHER_LOCAL_CUDA")
1104 |                 .map(|v| v == "1" || v.eq_ignore_ascii_case("true"))
1105 |                 .unwrap_or(false);
1106 |             let model_name = std::env::var("LOCAL_CUDA_MODEL")
1107 |                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_MODEL"))
1108 |                 .unwrap_or_else(|_| "qwen3.5-9b".to_string());
1109 |             let model_path = std::env::var("LOCAL_CUDA_MODEL_PATH")
1110 |                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_MODEL_PATH"))
1111 |                 .ok();
1112 |             let tokenizer_path = std::env::var("LOCAL_CUDA_TOKENIZER_PATH")
1113 |                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_TOKENIZER_PATH"))
1114 |                 .ok();
1115 |             let architecture = std::env::var("LOCAL_CUDA_ARCH")
1116 |                 .or_else(|_| std::env::var("CODETETHER_LOCAL_CUDA_ARCH"))
1117 |                 .ok();
1118 |             let has_model_env = std::env::var("LOCAL_CUDA_MODEL").is_ok()
1119 |                 || std::env::var("CODETETHER_LOCAL_CUDA_MODEL").is_ok();
1120 |             let has_local_cuda_config = has_model_env
1121 |                 || model_path.is_some()
1122 |                 || tokenizer_path.is_some()
1123 |                 || architecture.is_some();
1124 | 
1125 |             if local_cuda_enabled || has_local_cuda_config {
1126 |                 let provider = if let Some(path) = model_path {
1127 |                     local_cuda::LocalCudaProvider::with_paths(
1128 |                         model_name.clone(),
1129 |                         path,
1130 |                         tokenizer_path,
1131 |                         architecture,
1132 |                     )
1133 |                 } else {
1134 |                     local_cuda::LocalCudaProvider::new(model_name.clone())
1135 |                 };
1136 | 
1137 |                 match provider {
1138 |                     Ok(p) => {
1139 |                         tracing::info!(
1140 |                             model = %model_name,
1141 |                             "Registered local_cuda provider from environment"
1142 |                         );
1143 |                         registry.register(Arc::new(p));
1144 |                     }
1145 |                     Err(e) => tracing::warn!("Failed to init local_cuda from env: {}", e),
1146 |                 }
1147 |             }
1148 |         }
1149 |     }
1150 | }
