 use anyhow::Result;
 use async_trait::async_trait;
 use serde::{Deserialize, Serialize};
 use std::collections::HashMap;
 use std::sync::Arc;

 /// A message in a conversation
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct Message {
     pub role: Role,
     pub content: Vec<ContentPart>,
 }

 #[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
 #[serde(rename_all = "lowercase")]
 pub enum Role {
     System,
     User,
     Assistant,
     Tool,
 }

 #[derive(Debug, Clone, Serialize, Deserialize)]
 #[serde(tag = "type", rename_all = "snake_case")]
 pub enum ContentPart {
     Text {
         text: String,
     },
     Image {
         url: String,
         mime_type: Option<String>,
     },
     File {
         path: String,
         mime_type: Option<String>,
     },
     ToolCall {
         id: String,
         name: String,
         arguments: String,
         /// Thought signature for Gemini 3.x models - must be passed back when sending tool results
         #[serde(skip_serializing_if = "Option::is_none")]
         thought_signature: Option<String>,
     },
     ToolResult {
         tool_call_id: String,
         content: String,
     },
     Thinking {
         text: String,
     },
 }

 /// Tool definition for the model
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct ToolDefinition {
     pub name: String,
     pub description: String,
     pub parameters: serde_json::Value, // JSON Schema
 }

 /// Request to generate a completion
 #[derive(Debug, Clone)]
 pub struct CompletionRequest {
     pub messages: Vec<Message>,
     pub tools: Vec<ToolDefinition>,
     pub model: String,
     pub temperature: Option<f32>,
     pub top_p: Option<f32>,
     pub max_tokens: Option<usize>,
     pub stop: Vec<String>,
 }

 /// Request to generate embeddings
 #[derive(Debug, Clone)]
 pub struct EmbeddingRequest {
     pub model: String,
     pub inputs: Vec<String>,
 }

 /// Response from an embedding request
 #[derive(Debug, Clone)]
 pub struct EmbeddingResponse {
     pub embeddings: Vec<Vec<f32>>,
     pub usage: Usage,
 }

 /// A streaming chunk from the model
 #[derive(Debug, Clone)]
 pub enum StreamChunk {
     Text(String),
     ToolCallStart { id: String, name: String },
     ToolCallDelta { id: String, arguments_delta: String },
     ToolCallEnd { id: String },
     Done { usage: Option<Usage> },
     Error(String),
 }

 /// Token usage information
 #[derive(Debug, Clone, Default, Serialize, Deserialize)]
 pub struct Usage {
     pub prompt_tokens: usize,
     pub completion_tokens: usize,
     pub total_tokens: usize,
     pub cache_read_tokens: Option<usize>,
     pub cache_write_tokens: Option<usize>,
 }

 /// Response from a completion request
 #[derive(Debug, Clone)]
 pub struct CompletionResponse {
     pub message: Message,
     pub usage: Usage,
     pub finish_reason: FinishReason,
 }

 #[derive(Debug, Clone, Copy, Serialize, Deserialize, PartialEq, Eq)]
 #[serde(rename_all = "snake_case")]
 pub enum FinishReason {
     Stop,
     Length,
     ToolCalls,
     ContentFilter,
     Error,
 }

 /// Provider trait that all AI providers must implement
 #[async_trait]
 pub trait Provider: Send + Sync {
     /// Get the provider name
     fn name(&self) -> &str;

     /// List available models
     async fn list_models(&self) -> Result<Vec<ModelInfo>>;

     /// Generate a completion
     async fn complete(&self, request: CompletionRequest) -> Result<CompletionResponse>;

     /// Generate a streaming completion
     async fn complete_stream(
         &self,
         request: CompletionRequest,
     ) -> Result<futures::stream::BoxStream<'static, StreamChunk>>;

     /// Generate embeddings
     async fn embed(&self, _request: EmbeddingRequest) -> Result<EmbeddingResponse> {
         anyhow::bail!("Provider '{}' does not support embeddings", self.name())
     }
 }

 /// Information about a model
 #[derive(Debug, Clone, Serialize, Deserialize)]
 pub struct ModelInfo {
     pub id: String,
     pub name: String,
     pub provider: String,
     pub context_window: usize,
     pub max_output_tokens: Option<usize>,
     pub supports_vision: bool,
     pub supports_tools: bool,
     pub supports_streaming: bool,
     pub input_cost_per_million: Option<f64>,
     pub output_cost_per_million: Option<f64>,
 }

 /// Registry of available providers
 pub struct ProviderRegistry {
     providers: HashMap<String, Arc<dyn Provider>>,
 }

 impl std::fmt::Debug for ProviderRegistry {
     fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
         f.debug_struct("ProviderRegistry")
             .field("provider_count", &self.providers.len())
             .field("providers", &self.providers.keys().collect::<Vec<_>>())
             .finish()
     }
 }

 impl ProviderRegistry {
     pub fn new() -> Self {
         Self {
             providers: HashMap::new(),
         }
     }

     /// Register a provider (automatically wrapped with metrics instrumentation)
     pub fn register(&mut self, provider: Arc<dyn Provider>) {
         let name = provider.name().to_string();
         let wrapped = metrics::MetricsProvider::wrap(provider);
         self.providers.insert(name, wrapped);
